357→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
358→  LET $query = string::lowercase(string::trim($q));
359→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
360→
361→  LET $task_rows = SELECT
362→    id,
363→    "task" AS kind,
364→    title AS text,
365→    extraction_confidence AS confidence,
366→    source_message AS sourceMessage,
367→    priority,
368→    created_at
369→  FROM task
370→  WHERE workspace = $workspace
371→    AND extraction_confidence != NONE
372→    AND string::contains(string::lowercase(title), $query)
373→  ORDER BY created_at DESC
374→  LIMIT $safe_limit;
375→
376→  LET $decision_rows = SELECT
377→    id,
378→    "decision" AS kind,
379→    summary AS text,
380→    extraction_confidence AS confidence,
381→    source_message AS sourceMessage,
382→    priority,
383→    created_at
384→  FROM decision
385→  WHERE workspace = $workspace
386→    AND extraction_confidence != NONE
387→    AND string::contains(string::lowercase(summary), $query)
388→  ORDER BY created_at DESC
389→  LIMIT $safe_limit;
390→
391→  LET $question_rows = SELECT
392→    id,
393→    "question" AS kind,
394→    text AS text,
395→    extraction_confidence AS confidence,
396→    source_message AS sourceMessage,
397→    priority,
398→    created_at
399→  FROM question
400→  WHERE workspace = $workspace
401→    AND extraction_confidence != NONE
402→    AND string::contains(string::lowercase(text), $query)
403→  ORDER BY created_at DESC
404→  LIMIT $safe_limit;
405→
406→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
407→};
408→
409→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
410→  LET $query = string::lowercase(string::trim($q));
411→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
412→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
413→
414→  LET $task_rows = SELECT
415→    id,
416→    "task" AS kind,
417→    title AS text,
418→    extraction_confidence AS confidence,
419→    source_message AS sourceMessage,
420→    priority,
421→    created_at
422→  FROM task
423→  WHERE workspace = $workspace
424→    AND extraction_confidence != NONE
425→    AND id IN $project_entity_ids
426→    AND string::contains(string::lowercase(title), $query)
427→  ORDER BY created_at DESC
428→  LIMIT $safe_limit;
429→
430→  LET $decision_rows = SELECT
431→    id,
432→    "decision" AS kind,
433→    summary AS text,
434→    extraction_confidence AS confidence,
435→    source_message AS sourceMessage,
436→    priority,
437→    created_at
438→  FROM decision
439→  WHERE workspace = $workspace
440→    AND extraction_confidence != NONE
441→    AND id IN $project_entity_ids
442→    AND string::contains(string::lowercase(summary), $query)
443→  ORDER BY created_at DESC
444→  LIMIT $safe_limit;
445→
446→  LET $question_rows = SELECT
447→    id,
448→    "question" AS kind,
449→    text AS text,
450→    extraction_confidence AS confidence,
451→    source_message AS sourceMessage,
452→    priority,
453→    created_at
454→  FROM question
455→  WHERE workspace = $workspace
456→    AND extraction_confidence != NONE
457→    AND id IN $project_entity_ids
458→    AND string::contains(string::lowercase(text), $query)
459→  ORDER BY created_at DESC
460→  LIMIT $safe_limit;
461→
462→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
463→};
464→
465→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
466→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
467→  RETURN SELECT id, role, text, createdAt
468→  FROM message
469→  WHERE conversation = $conversation
470→  ORDER BY createdAt DESC
471→  LIMIT $safe_limit;
472→};
473→
474→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
475→  RETURN SELECT
476→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
477→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
478→  FROM $entity;
479→};
